// pages/practice/practice.js
const app = getApp();

Page({
  data: {
    duration: 3,
    mode: 'guided',
    remainingTime: 180, // 秒
    totalTime: 180,
    isPlaying: false,
    isCompleted: false,
    isPaused: false,
    progress: 0,
    formatTime: '03:00',
    currentGuide: '',
    rating: 0,
    notes: '',
    actualDuration: 0,
    currentTip: '保持脊柱自然挺直，放松肩膀',
    tips: [
      '保持脊柱自然挺直，放松肩膀',
      '呼吸自然，不要刻意控制',
      '心跑掉了，轻轻拉回来就好',
      '不评判，只是觉察',
      '享受这片刻的宁静'
    ]
  },

  timer: null,
  audioContext: null,
  startTime: null,

  onLoad(options) {
    const duration = parseInt(options.duration) || 3;
    const mode = options.mode || 'guided';
    const totalTime = duration * 60;

    this.setData({
      duration,
      mode,
      remainingTime: totalTime,
      totalTime,
      formatTime: this.formatTime(totalTime)
    });

    // 初始化音频
    if (mode === 'guided') {
      this.initAudio();
    }
  },

  onUnload() {
    this.clearTimer();
    if (this.audioContext) {
      this.audioContext.stop();
    }
  },

  // 初始化音频
  initAudio() {
    this.audioContext = wx.createInnerAudioContext();
    // 这里应该使用实际的音频文件URL
    // this.audioContext.src = `https://your-cdn.com/audio/${this.data.duration}min.mp3`;
  },

  // 格式化时间
  formatTime(seconds) {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  },

  // 获取当前阶段文字
  getStageText() {
    const { totalTime, remainingTime } = this.data;
    const elapsed = totalTime - remainingTime;
    const progress = elapsed / totalTime;

    if (progress < 0.17) return '调身';
    if (progress < 0.67) return '调息';
    if (progress < 0.89) return '观心';
    return '收功';
  },

  // 更新引导文字
  updateGuideText() {
    const { mode, totalTime, remainingTime } = this.data;
    if (mode !== 'guided') return;

    const elapsed = totalTime - remainingTime;
    const progress = elapsed / totalTime;

    let guide = '';
    if (progress < 0.17) {
      guide = '让身体自然放松，脊柱轻轻挺直';
    } else if (progress < 0.67) {
      guide = '吸气...呼气...保持自然的呼吸节奏';
    } else if (progress < 0.89) {
      guide = '觉察身体的感觉，不评判，只是知道';
    } else {
      guide = '慢慢把觉知带回，准备结束练习';
    }

    this.setData({ currentGuide: guide });
  },

  // 开始练习
  startPractice() {
    this.setData({ isPlaying: true, isPaused: false });
    this.startTime = new Date();

    if (this.data.mode === 'guided' && this.audioContext) {
      this.audioContext.play();
    }

    this.startTimer();
  },

  // 暂停练习
  pausePractice() {
    this.clearTimer();
    this.setData({ isPlaying: false, isPaused: true });

    if (this.audioContext) {
      this.audioContext.pause();
    }
  },

  // 结束练习
  endPractice() {
    this.clearTimer();
    const actualDuration = Math.floor((new Date() - this.startTime) / 1000 / 60);

    this.setData({
      isPlaying: false,
      isCompleted: true,
      actualDuration: actualDuration < 1 ? 1 : actualDuration
    });

    if (this.audioContext) {
      this.audioContext.stop();
    }
  },

  // 计时器
  startTimer() {
    this.timer = setInterval(() => {
      const { remainingTime, totalTime } = this.data;

      if (remainingTime <= 0) {
        this.endPractice();
        return;
      }

      const newTime = remainingTime - 1;
      const progress = ((totalTime - newTime) / totalTime) * 100;

      this.setData({
        remainingTime: newTime,
        formatTime: this.formatTime(newTime),
        progress
      });

      this.updateGuideText();

      // 每30秒更换提示
      if (newTime % 30 === 0) {
        const tips = this.data.tips;
        const randomTip = tips[Math.floor(Math.random() * tips.length)];
        this.setData({ currentTip: randomTip });
      }
    }, 1000);
  },

  clearTimer() {
    if (this.timer) {
      clearInterval(this.timer);
      this.timer = null;
    }
  },

  // 返回
  goBack() {
    if (this.data.isPlaying) {
      wx.showModal({
        title: '确认退出',
        content: '练习正在进行中，确定要退出吗？',
        success: (res) => {
          if (res.confirm) {
            wx.navigateBack();
          }
        }
      });
    } else {
      wx.navigateBack();
    }
  },

  // 设置评分
  setRating(e) {
    const rating = e.currentTarget.dataset.rating;
    this.setData({ rating });
  },

  // 输入备注
  onNotesInput(e) {
    this.setData({ notes: e.detail.value });
  },

  // 保存练习记录
  savePractice() {
    const { duration, rating, notes, actualDuration } = this.data;

    const record = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      duration: actualDuration * 60,
      plannedDuration: duration,
      rating,
      notes,
      mode: this.data.mode
    };

    app.savePractice(record);

    wx.showToast({
      title: '保存成功',
      icon: 'success'
    });

    setTimeout(() => {
      wx.switchTab({ url: '/pages/stats/stats' });
    }, 1500);
  }
});

