                        <span class="option-unit">适合初学</span>
                    </div>
                    <div class="option" onclick="selectMode('silent')">
                        <span class="option-number">自主</span>
                        <span class="option-unit">适合熟练</span>
                    </div>
                </div>
            </div>
        </div>

        <!-- 练习页面 -->
        <div id="practicePage" class="page practice-page">
            <div class="breath-bg" id="breathBg"></div>

            <div class="practice-header">
                <div class="back-btn" onclick="goBack()">← 返回</div>
                <div class="practice-info">
                    <div class="practice-duration" id="practiceDuration">3分钟止观</div>
                    <div class="practice-mode" id="practiceMode">引导练习</div>
