// 初始化
document.addEventListener('DOMContentLoaded', () => {
    setGreeting();
    updateHomeStats();
    updateStatsPage();
    initAudio();
});

// 初始化音频上下文
function initAudio() {
    try {
        audioContext = new (window.AudioContext || window.webkitAudioContext)();
    } catch (e) {
        console.log('Web Audio API not supported');
        audioEnabled = false;
    }
}

// 播放提示音 - 磬声
function playBellSound(frequency = 528, duration = 2, type = 'sine') {
    if (!audioEnabled || !audioContext) return;

    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);

    oscillator.frequency.value = frequency;
    oscillator.type = type;

    // 渐强渐弱包络
    const now = audioContext.currentTime;
    gainNode.gain.setValueAtTime(0, now);
    gainNode.gain.linearRampToValueAtTime(audioVolume * 0.3, now + 0.1);
    gainNode.gain.exponentialRampToValueAtTime(audioVolume * 0.1, now + duration * 0.5);
    gainNode.gain.exponentialRampToValueAtTime(0.001, now + duration);

    oscillator.start(now);
    oscillator.stop(now + duration);
}

// 播放风铃声
function playChimeSound() {
    if (!audioEnabled || !audioContext) return;

    // 主音
    playBellSound(528, 1.5, 'sine');
    // 泛音
    setTimeout(() => playBellSound(1056, 1, 'sine'), 50);
    setTimeout(() => playBellSound(1584, 0.8, 'sine'), 100);
}

// 播放水滴声
function playWaterDropSound() {
    if (!audioEnabled || !audioContext) return;

    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);

    oscillator.frequency.setValueAtTime(800, audioContext.currentTime);
    oscillator.frequency.exponentialRampToValueAtTime(400, audioContext.currentTime + 0.3);
    oscillator.type = 'sine';

    const now = audioContext.currentTime;
    gainNode.gain.setValueAtTime(0, now);
    gainNode.gain.linearRampToValueAtTime(audioVolume * 0.2, now + 0.02);
    gainNode.gain.exponentialRampToValueAtTime(0.001, now + 0.3);

    oscillator.start(now);
    oscillator.stop(now + 0.3);
}

// 播放结束音（三声磬音）
function playEndSound() {
    if (!audioEnabled || !audioContext) return;

    playBellSound(528, 2, 'sine');
    setTimeout(() => playBellSound(528, 2, 'sine'), 800);
    setTimeout(() => playBellSound(528, 3, 'sine'), 1600);
}

// 根据阶段播放提示音
function playStageSound(stage) {
    if (!audioEnabled) return;

    switch(stage) {
        case 'start':
            playBellSound(396, 2); // 开始 - 低沉磬声
            break;
        case 'tiaoshen':
            case 'tiaoxi':
        case 'guanxin':
            playWaterDropSound(); // 阶段切换 - 水滴声
            break;
        case 'shougong':
            playChimeSound(); // 收功 - 风铃声
            break;
        case 'end':
            playEndSound(); // 结束 - 三声磬音
            break;
    }
}

