let audioContext = null, audioEnabled = true, audioVolume = 1.0;
let lastMinuteMark = 0;
let preEndWarningPlayed = false;

document.addEventListener('DOMContentLoaded', () => {
    setGreeting();
    updateHomeStats();
    updateStatsPage();
    initAudio();
});

function initAudio() {
    try { audioContext = new (window.AudioContext || window.webkitAudioContext)(); }
    catch (e) { audioEnabled = false; }
}

// 磬声 - 浑厚悠扬如波荡漾
function playBellSound(frequency = 528, duration = 3, type = 'sine') {
    if (!audioEnabled || !audioContext) return;

    const now = audioContext.currentTime;

    // 主音 - 使用triangle波形增加浑厚感
    const mainOsc = audioContext.createOscillator();
    const mainGain = audioContext.createGain();
    mainOsc.connect(mainGain);
    mainGain.connect(audioContext.destination);

    mainOsc.frequency.value = frequency;
    mainOsc.type = 'triangle';

    // 缓慢起音，悠长衰减
    mainGain.gain.setValueAtTime(0, now);
    mainGain.gain.linearRampToValueAtTime(audioVolume * 0.5, now + 0.3);
    mainGain.gain.exponentialRampToValueAtTime(audioVolume * 0.3, now + duration * 0.4);
    mainGain.gain.exponentialRampToValueAtTime(0.001, now + duration);

    mainOsc.start(now);
    mainOsc.stop(now + duration);

    // 泛音 - 增加通透感
    const harmonicOsc = audioContext.createOscillator();
    const harmonicGain = audioContext.createGain();
    harmonicOsc.connect(harmonicGain);
    harmonicGain.connect(audioContext.destination);

    harmonicOsc.frequency.value = frequency * 2;
    harmonicOsc.type = 'sine';

    harmonicGain.gain.setValueAtTime(0, now);
    harmonicGain.gain.linearRampToValueAtTime(audioVolume * 0.15, now + 0.2);
    harmonicGain.gain.exponentialRampToValueAtTime(0.001, now + duration * 0.6);

    harmonicOsc.start(now);
    harmonicOsc.stop(now + duration * 0.6);

    // 低频基音 - 增加浑厚感
    const bassOsc = audioContext.createOscillator();
    const bassGain = audioContext.createGain();
    bassOsc.connect(bassGain);
    bassGain.connect(audioContext.destination);

    bassOsc.frequency.value = frequency * 0.5;
    bassOsc.type = 'sine';

    bassGain.gain.setValueAtTime(0, now);
    bassGain.gain.linearRampToValueAtTime(audioVolume * 0.25, now + 0.4);
    bassGain.gain.exponentialRampToValueAtTime(0.001, now + duration);

    bassOsc.start(now);
    bassOsc.stop(now + duration);
}

// 开始 - 三声磬声
function playStartSound() {
    if (!audioEnabled || !audioContext) return;
    playBellSound(396, 4); // 低沉浑厚
    setTimeout(() => playBellSound(396, 4), 1200);
    setTimeout(() => playBellSound(396, 5), 2400);
}

// 结束 - 一声磬声
function playEndSound() {
    if (!audioEnabled || !audioContext) return;
    playBellSound(528, 6);
}

// 风铃声 - 轻盈通透
function playChimeSound() {
    if (!audioEnabled || !audioContext) return;

    const now = audioContext.currentTime;
    const baseFreq = 528;

    // 多音叠加营造风铃效果
    const frequencies = [baseFreq, baseFreq * 1.5, baseFreq * 2, baseFreq * 2.5];
    const delays = [0, 0.1, 0.2, 0.3];

    frequencies.forEach((freq, i) => {
        const osc = audioContext.createOscillator();
        const gain = audioContext.createGain();
        osc.connect(gain);
        gain.connect(audioContext.destination);

        osc.frequency.value = freq;
        osc.type = 'sine';

        gain.gain.setValueAtTime(0, now + delays[i]);
        gain.gain.linearRampToValueAtTime(audioVolume * 0.2, now + delays[i] + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, now + delays[i] + 1.5);

        osc.start(now + delays[i]);
        osc.stop(now + delays[i] + 1.5);
    });
}

// 水滴声 - 清脆有穿透力
function playWaterDropSound() {
    if (!audioEnabled || !audioContext) return;

    const now = audioContext.currentTime;

    // 主音 - 高频清脆
    const osc = audioContext.createOscillator();
    const gain = audioContext.createGain();
    osc.connect(gain);
    gain.connect(audioContext.destination);

    osc.frequency.setValueAtTime(1200, now);
    osc.frequency.exponentialRampToValueAtTime(600, now + 0.15);
    osc.type = 'sine';

    gain.gain.setValueAtTime(0, now);
    gain.gain.linearRampToValueAtTime(audioVolume * 0.4, now + 0.01);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);

    osc.start(now);
    osc.stop(now + 0.15);

    // 泛音 - 增加穿透力
    const harmonic = audioContext.createOscillator();
    const harmonicGain = audioContext.createGain();
    harmonic.connect(harmonicGain);
    harmonicGain.connect(audioContext.destination);

    harmonic.frequency.setValueAtTime(2400, now);
    harmonic.frequency.exponentialRampToValueAtTime(1200, now + 0.1);
    harmonic.type = 'sine';

    harmonicGain.gain.setValueAtTime(0, now);
    harmonicGain.gain.linearRampToValueAtTime(audioVolume * 0.15, now + 0.005);
    harmonicGain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);

    harmonic.start(now);
    harmonic.stop(now + 0.1);
}

// 结束前30秒提醒 - 3秒风铃声
function playPreEndWarning() {
    if (!audioEnabled || !audioContext) return;

    const now = audioContext.currentTime;
    const baseFreq = 528;

    // 3秒内连续风铃音
    for (let i = 0; i < 5; i++) {
        setTimeout(() => {
            const osc = audioContext.createOscillator();
            const gain = audioContext.createGain();
            osc.connect(gain);
            gain.connect(audioContext.destination);

            osc.frequency.value = baseFreq + (i * 100);
            osc.type = 'sine';

            const startTime = audioContext.currentTime;
            gain.gain.setValueAtTime(0, startTime);
            gain.gain.linearRampToValueAtTime(audioVolume * 0.15, startTime + 0.02);
            gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.8);

            osc.start(startTime);
            osc.stop(startTime + 0.8);
        }, i * 600);
    }
}

function toggleAudio() {
    audioEnabled = !audioEnabled;
    document.getElementById('audioControl').textContent = audioEnabled ? '🔔 提示音: 开' : '🔕 提示音: 关';
}

