function startTimer() {
    if (audioContext && audioContext.state === 'suspended') audioContext.resume();
    isPlaying = true;
    currentPractice.startTime = new Date();
    lastMinuteMark = 0;
    preEndWarningPlayed = false;

    // 播放开始提示音 - 三声磬声
    playStartSound();

    document.getElementById('breathBg').classList.add('breathing');
    document.getElementById('practiceControls').innerHTML = `
        <button class="control-btn pause" onclick="pauseTimer()">暂停</button>
        <button class="control-btn end" onclick="endPractice()">结束</button>
    `;

    timer = setInterval(() => {
        remainingTime--;
        document.getElementById('timer').textContent = formatTime(remainingTime);
        const progress = ((totalTime - remainingTime) / totalTime) * 100;
        document.getElementById('progressFill').style.width = `${progress}%`;
        document.getElementById('progressText').textContent = `${Math.floor(progress)}%`;

        updateStageLabel();
        updateGuideText();

        // 超过3分钟后，每分钟水滴声
        const elapsedMinutes = Math.floor((totalTime - remainingTime) / 60);
        if (totalTime > 180 && elapsedMinutes > lastMinuteMark && elapsedMinutes >= 3) {
            playWaterDropSound();
            lastMinuteMark = elapsedMinutes;
        }

        // 结束前30秒提醒
        if (remainingTime === 30 && !preEndWarningPlayed) {
            playPreEndWarning();
            preEndWarningPlayed = true;
        }

        if (remainingTime <= 0) {
            endPractice();
        }
    }, 1000);
}

